import React, { useState, useEffect } from 'react';
import AxiosInstance from '../../axiosinstance';
import { useNavigate } from 'react-router-dom';
import './writing.css';

const WritingLandingPage = () => {
  const [posts, setPosts] = useState([]);
  const navigate = useNavigate();

  const getPostData = async () => {
    try {
      const response = await AxiosInstance.get('/writing/');
      if (response.status === 200) {
        setPosts(response.data);
      } else {
        console.error('Error fetching data: Response is undefined or status is not 200');
      }
    } catch (error) {
      console.error('Error fetching data:', error.response?.data || error);
    }
  };

  useEffect(() => {
    getPostData();
  }, []);

  const sortedPosts = [...posts].sort(
    (a, b) => new Date(b.created_on) - new Date(a.created_on)
  );

  const handlePostClick = (postId) => {
    navigate(`/writing/${postId}`);
  };

  return (
    <main className="writing-page">
      <section className="writing-hero">
        <h1 className="page-heading projects-heading">Projects</h1>
        <p className="writing-intro">
          Articles, reflections, and notes on software, books, and the ideas
          I keep returning to.
        </p>
      </section>

      <section className="writing-grid-section">
        {sortedPosts.length === 0 ? (
          <div className="writing-loading">Loading...</div>
        ) : (
          <div className="writing-grid">
            {sortedPosts.map((post) => (
              <article className="writing-block" key={post.id}>
                <div className="writing-block-top">
                  <h2
                    className="writing-title"
                    onClick={() => handlePostClick(post.id)}
                  >
                    {post.title}
                  </h2>

                  <div className="writing-meta">
                    <p>
                      Publication date:{' '}
                      {new Date(post.publication_date).toLocaleDateString('en-GB', {
                        day: '2-digit',
                        month: 'long',
                        year: 'numeric',
                      })}
                    </p>
                    <p>
                      Created on:{' '}
                      {new Date(post.created_on).toLocaleDateString('en-GB', {
                        day: '2-digit',
                        month: 'long',
                        year: 'numeric',
                      })}
                    </p>
                  </div>

                  <p className="writing-excerpt">
                    {post.body.length > 140
                      ? `${post.body.substring(0, 140)}...`
                      : post.body}
                  </p>
                </div>

                <button
                  className="writing-read-more"
                  onClick={() => handlePostClick(post.id)}
                >
                  Read more
                </button>
              </article>
            ))}
          </div>
        )}
      </section>
    </main>
  );
};

export default WritingLandingPage;
